    step2t: { ru: 'ИИ анализирует видео', en: 'AI reads the whole video', es: 'La IA lee todo el video', fr: 'L\'IA lit toute la vidéo', de: 'KI liest das ganze Video', pt: 'IA lê o vídeo inteiro', it: 'L\'IA legge tutto il video', tr: 'Yapay zeka videoyu okur', ar: 'الذكاء الاصطناعي يقرأ الفيديو كاملاً', ko: 'AI가 영상 전체 분석', zh: 'AI分析整个视频', ja: 'AIが動画全体を分析' },
    step2d: { ru: 'ИИ анализирует кадры по всему видео — начало, середина, петля.', en: 'AI analyzes frames across the entire video — opening, middle, and loop hook.', es: 'La IA analiza fotogramas en todo el video — apertura, medio y bucle.', fr: 'L\'IA analyse les images sur toute la vidéo — ouverture, milieu et boucle.', de: 'KI analysiert Frames über das gesamte Video — Öffnung, Mitte und Loop.', pt: 'IA analisa frames em todo o vídeo — abertura, meio e loop.', it: 'L\'IA analizza i frame dell\'intero video — apertura, metà e loop.', tr: 'Yapay zeka tüm video boyunca kareleri analiz eder — açılış, orta, döngü.', ar: 'الذكاء الاصطناعي يحلل الإطارات عبر الفيديو — الافتتاح والوسط والحلقة.', ko: 'AI가 영상 전체 프레임 분석 — 오프닝, 중간, 루프 훅.', zh: 'AI分析整个视频的帧 — 开头、中间和循环。', ja: 'AIが動画全体のフレームを分析 — 冒頭、中盤、ループフック。' },
    step3t: { ru: 'Получи готовые скрипты', en: 'Get hook scripts', es: 'Obtén scripts de hook', fr: 'Obtiens des scripts de hook', de: 'Hook-Skripte erhalten', pt: 'Obtenha scripts de hook', it: 'Ottieni gli script di hook', tr: 'Hook senaryoları al', ar: 'احصل على سكريبتات الهوك', ko: '훅 스크립트 받기', zh: '获取钩子脚本', ja: 'フックスクリプトを取得' },
    step3d: { ru: 'Готовые скрипты для каждого слабого момента — тип, место, скопируй и используй.', en: 'Custom scripts for each weak moment — type, placement, copy-ready.', es: 'Scripts personalizados para cada momento débil — tipo, ubicación, listo para copiar.', fr: 'Scripts personnalisés pour chaque moment faible — type, placement, prêt à copier.', de: 'Benutzerdefinierte Skripte für jeden schwachen Moment — Typ, Platzierung, kopierfertig.', pt: 'Scripts personalizados para cada momento fraco — tipo, posição, pronto para copiar.', it: 'Script personalizzati per ogni momento debole — tipo, posizione, pronto da copiare.', tr: 'Her zayıf an için özel senaryolar — tür, konum, kopyalamaya hazır.', ar: 'سكريبتات مخصصة لكل لحظة ضعف — النوع والموضع وجاهز للنسخ.', ko: '각 약점마다 맞춤 스크립트 — 유형, 위치, 바로 복사 가능.', zh: '针对每个弱点的定制脚本 — 类型、位置、可直接复制。', ja: '各弱点箇所のカスタムスクリプト — タイプ、配置、コピー即使用。' },
    ctaTitle: { ru: 'Твой анализ. Только твой.', en: 'Your analysis. Only yours.', es: 'Tu análisis. Solo tuyo.', fr: 'Ton analyse. Rien que pour toi.', de: 'Deine Analyse. Nur deine.', pt: 'Sua análise. Só sua.', it: 'La tua analisi. Solo tua.', tr: 'Senin analizin. Sadece senin.', ar: 'تحليلك. لك وحدك.', ko: '나만의 분석. 오직 나만의.', zh: '你的分析。只属于你。', ja: 'あなたの分析。あなただけのもの。' },
    ctaSub: { ru: 'Результаты приватны и сохраняются в браузере. Без аккаунта. Просто загрузи видео и получи анализ.', en: 'Results are private and saved to your browser. No account needed. Just upload your video and get your confidential hook analysis.', es: 'Los resultados son privados. Sin cuenta. Solo sube tu video y obtén tu análisis.', fr: 'Les résultats sont privés. Sans compte. Télécharge ta vidéo et obtiens ton analyse.', de: 'Ergebnisse sind privat. Kein Konto. Lade dein Video hoch und erhalte deine Analyse.', pt: 'Resultados privados. Sem conta. Envie seu vídeo e obtenha sua análise.', it: 'Risultati privati. Nessun account. Carica il video e ottieni la tua analisi.', tr: 'Sonuçlar gizli. Hesap gerekmez. Videonuzu yükleyin ve analizinizi alın.', ar: 'النتائج خاصة. بدون حساب. ارفع الفيديو واحصل على التحليل.', ko: '결과는 비공개. 계정 불필요. 영상을 올리고 분석을 받으세요.', zh: '结果保密存储。无需账号。上传视频即可获得分析。', ja: '結果はプライベート。アカウント不要。動画をアップして分析を受け取りましょう。' },
    ctaBtn: { ru: 'Анализировать бесплатно', en: 'Analyze My Reels Free', es: 'Analizar mis Reels gratis', fr: 'Analyser gratuitement', de: 'Kostenlos analysieren', pt: 'Analisar grátis', it: 'Analizza gratis', tr: 'Ücretsiz analiz et', ar: 'تحليل مجاناً', ko: '무료 분석하기', zh: '免费分析', ja: '無料で分析' },
